                }

                disposableResources.Push(command);

                command.CommandTimeout = Framework.Constants.DefaultDatabaseCommandTimeout;

                command.CommandType = CommandType.Text;
                command.CommandText = updateSql;

                if (condition == null)
                {
                    command.CommandText += "\r\nWHERE\r\n" + updateDefaultConditionSql;
                }
                else
                {
                    command.Parameters.AddRange(parameters);
                    command.CommandText += "\r\nWHERE\r\n" + condition;
                }

                command.Parameters.Add(new SqlParameter("ID", SqlDbType.Int)).Value = (object)entity.ID ?? DBNull.Value;
                command.Parameters.Add(new SqlParameter("SurveyId", SqlDbType.Int)).Value = (object)entity.SurveyId ?? DBNull.Value;
                command.Parameters.Add(new SqlParameter("FiredTime", SqlDbType.DateTime)).Value = (object)entity.FiredTime ?? DBNull.Value;
